content.content:
1	import { _decorator, Component, Label, Node, sp, tween, Tween, UIOpacity, warn } from 'cc';
2	import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
3	import Game_Define, { IBountyData, Symbol } from '../Game_Define';
4	const { ccclass, property } = _decorator;
5	
6	/**@ch 懸賞單 Spine 動畫名稱（常駐用 In/Out/Mark/Mark_Idle/Mark_Active，場上實例用 Symbol_In/Symbol_Active）*/
7	const ANIM = {
8	    IN: 'In',
9	    OUT: 'Out',
10	    MARK: 'Mark',
11	    MARK_IDLE: 'Mark_Idle',
12	    MARK_ACTIVE: 'Mark_Active',
13	    SYMBOL_IN: 'Symbol_In',
14	    SYMBOL_ACTIVE: 'Symbol_Active',
15	} as const;
16	
17	/**
18	 * @ch 依 Symbol 取對應 skin 名稱（M1~M9）
19	 * 利用 enum 反查（Symbol[Symbol.M1] === 'M1'），skin 名與 enum 名一致
20	 * @returns 'M1'~'M9'；超出範圍回 null
21	 */
22	function GetSkinNameBySymbol( symbolId: Symbol ): string | null {
23	    if ( symbolId < Symbol.M1 || symbolId > Symbol.M9 ) return null;
24	    return Symbol[ symbolId ] ?? null;
25	}
26	
27	/**
28	 * @ch 常駐懸賞單元件 — 播放 In / Out / Mark / Mark_Active 動畫
29	 * 倍率數字節點掛在 prefab 階層內，由 NewBoneFollow + NewSlotColorFollow 元件
30	 * 自動跟隨 spine 的 Wanted_NUM bone / slot（純編輯器設定，本元件不處理）
31	 */
32	@ccclass('WantedPosterItem')
33	export class WantedPosterItem extends Component {
34	    //#region Properties
35	    @property({
36	        type: sp.Skeleton,
37	        tooltip: '懸賞單 Spine（含 Wanted.skel）'
38	    })
39	    private m_spine: sp.Skeleton = null;
40	
41	    @property({
42	        type: Label,
43	        tooltip: '懸賞倍率（位置由 NewBoneFollow 跟隨 Wanted_NUM bone）'
44	    })
45	    private m_multiplierLabel: Label = null;
46	
47	    @property({
48	        type: UIOpacity,
49	        tooltip: '懸賞倍率透明度'
50	    })
51	    private m_multiplierLabelUIOpacity: UIOpacity = null;
52	
53	    @property({
54	        type: Node,
55	        tooltip: '懸賞倍率X9999 節點'
56	    })
57	    private m_x9999Node: Node = null;
58	
59	    @property({
60	        type: UIOpacity,
61	        tooltip: '懸賞倍率X9999透明度'
62	    })
63	    private m_x9999UIOpacity: UIOpacity = null;
64	
65	    @property({
66	        type: Node,
67	        tooltip: '內容容器（Spine + 倍率）。ghost 佔位時關閉此節點：內容隱形但 item root 仍被 cc.Layout 計入版位'
68	    })
69	    private m_contentNode: Node = null;
70	    //#endregion Properties
71	
72	    //#region Variables
73	    /**@ch 當前綁定的 BaseSymbol*/
74	    private m_baseSymbol: Symbol = Symbol.MAX;
75	
76	    /**@ch 倍率 label 淡出時長（秒）*/
77	    private static readonly MULTIPLIER_FADE_OUT_DURATION: number = 0.1;
78	    //#endregion Variables
79	
80	    //#region Public API
81	    /**
82	     * @ch 設置懸賞單資料：切 skin、設數字、紀錄 BaseSymbol（不負責動畫觸發，由 Manager 決定）
83	     * @param data 懸賞單資料
84	     */
85	    public SetWantedPosterData( data: IBountyData ): void {
86	        this.m_baseSymbol = data.BaseSymbol as Symbol;
87	        this.SetSkinBySymbol( this.m_baseSymbol );
88	        this.SetMultiplierLabel( data.Multiple );
89	    }
90	
91	    /**@ch 取得當前綁定的 BaseSymbol（State 比對用）*/
92	    public GetBaseSymbol(): Symbol {
93	        return this.m_baseSymbol;
94	    }
95	
96	    /**
97	     * @ch 設定內容可見性（ghost slot 機制）：關閉時 Spine/倍率隱形，但 item root 仍被 cc.Layout 計入版位
98	     * EH：m_contentNode 未設置 → warn 不拋例外
99	     */
100	    public SetContentVisible( visible: boolean ): void {
101	        if ( !this.m_contentNode ) {
102	            warn( '[WantedPosterItem] SetContentVisible: m_contentNode 未設置' );
103	            return;
104	        }
105	        this.m_contentNode.active = visible;
106	    }
107	
108	    /**@ch 清除綁定的 BaseSymbol（ghost 化時呼叫，避免 GetBaseSymbol 回傳殘留舊符號髒值）*/
109	    public ClearBaseSymbol(): void {
110	        this.m_baseSymbol = Symbol.MAX;
111	    }
112	
113	    /**@ch 播 In 動畫，等播完（重設倍率 opacity 為 255，開啟新展示週期）*/
114	    public PlayIn(): Promise<void> {
115	        this.ResetMultiplierOpacity();
116	        return this.PlayAnim( ANIM.IN, false );
117	    }
118	
119	    /**@ch 播 Out 動畫，等播完*/
120	    public PlayOut(): Promise<void> {
121	        return this.PlayAnim( ANIM.OUT, false );
122	    }
123	
124	    /**
125	     * @ch 直接顯示 In 動畫「已定位」的最後一幀靜止畫面（不播進場過程）
126	     * 用於 GAME_INTRO_COMPLETE：介紹已演完進場，這裡只要呈現定位完成的結果。
127	     * 取樣尾幀使 bone 落到 In 終點，倍率數字（NewBoneFollow 跟 Wanted_NUM bone）才會正確對位。
128	     * EH-1：m_spine 為 null → warn + 略過
129	     */
130	    public ShowInSettled(): void {
131	        this.ResetMultiplierOpacity();
132	        if ( !this.m_spine ) {
133	            warn( '[WantedPosterItem] ShowInSettled: m_spine 未設置' );
134	            return;
135	        }
136	        const entry = this.m_spine.setAnimation( 0, ANIM.IN, false );
137	        if ( entry ) entry.trackTime = entry.animationEnd;  // 跳到 In 最後一幀
138	        this.m_spine.updateAnimation( 0 );                  // 立即取樣套用該幀姿勢（當幀定位、不閃）
139	    }
140	
141	    /**
142	     * @ch 播 Mark，等 Mark 完成；完成後自動接 Mark_Idle loop（不等待 loop）
143	     * @returns Mark 動畫完成的 Promise（不含 Mark_Idle loop）
144	     */
145	    public async PlayMark(): Promise<void> {
146	        await this.PlayAnim( ANIM.MARK, false );
147	        // EH-1：若 spine 為 null，PlayAnim 已 warn 並 resolve；此處不再 addAnimation
148	        if ( !this.m_spine ) return;
149	        // 接 Mark_Idle loop 在 track 0（會被後續 PlayMarkActive 的 setAnimation 自動取代）
150	        this.m_spine.addAnimation( 0, ANIM.MARK_IDLE, true, 0 );
151	    }
152	
153	    /**@ch 播 Mark_Active（會打斷 Mark_Idle loop；同步淡出倍率 label）*/
154	    public PlayMarkActive(): Promise<void> {
155	        this.FadeOutMultiplierOpacity();
156	        return this.PlayAnim( ANIM.MARK_ACTIVE, false );
157	    }
158	
159	    /**@ch 播 Symbol_In，等播完（loop=false → stay at last frame；重設倍率 opacity 為 255）— 場上實例用 */
160	    public PlaySymbolIn(): Promise<void> {
161	        this.ResetMultiplierOpacity();
162	        return this.PlayAnim( ANIM.SYMBOL_IN, false );
163	    }
164	
165	    /**@ch 播 Symbol_Active，等播完（同步淡出倍率 label）— 場上實例用 */
166	    public PlaySymbolActive(): Promise<void> {
167	        this.FadeOutMultiplierOpacity();
168	        return this.PlayAnim( ANIM.SYMBOL_ACTIVE, false );
169	    }
170	
171	    /**
172	     * @ch 公開 skin 切換 API（場上實例用，不走 SetWantedPosterData 因為不需要設 multiplier label）
173	     * EH-2：Symbol 不在 M1~M9 範圍 → warn + 不切
174	     */
175	    public SetSkin( symbolId: Symbol ): void {
176	        this.m_baseSymbol = symbolId;
177	        this.SetSkinBySymbol( symbolId );
178	    }
179	
180	    /**
181	     * @ch 場上實例設定倍率顯示（合併組連乘值，純表演）；須在 SetSkin 之後呼叫
182	     * IF-2：委派既有 private SetMultiplierLabel，避免格式字串重複；label 為 null 時靜默（EH-3）
183	     */
184	    public SetFieldMultiplier( multiplier: number ): void {
185	        this.SetMultiplierLabel( multiplier );
186	    }
187	    //#endregion Public API
188	
189	    //#region Private
190	    /**
191	     * @ch 依 Symbol 切 skin（M1~M9）
192	     * EH-2：Symbol 不在範圍 → warn + 不切
193	     */
194	    private SetSkinBySymbol( symbolId: Symbol ): void {
195	        if ( !this.m_spine ) {
196	            warn( '[WantedPosterItem] SetSkinBySymbol: m_spine 未設置' );
197	            return;
198	        }
199	        const skinName = GetSkinNameBySymbol( symbolId );
200	        if ( !skinName ) {
201	            warn( '[WantedPosterItem] SetSkinBySymbol: Symbol 不在 M1~M9 範圍', symbolId );
202	            return;
203	        }
204	        this.m_spine.setSkin( skinName );
205	        this.m_spine.setSlotsToSetupPose();
206	    }
